import{_ as o,C as d,o as e,c as A,a5 as a,b as E,w as r,a as i,E as l,a4 as s}from"./chunks/framework.sOZL8giL.js";const b=JSON.parse('{"title":"长运行Agent","description":"","frontmatter":{},"headers":[],"relativePath":"02-上下文工程/05-长运行Agent.md","filePath":"02-上下文工程/05-长运行Agent.md","lastUpdated":null}'),p={name:"02-上下文工程/05-长运行Agent.md"};function h(B,t,g,c,u,C){const n=d("Mermaid");return e(),A("div",null,[t[1]||(t[1]=a('<h1 id="长运行agent" tabindex="-1">长运行Agent <a class="header-anchor" href="#长运行agent" aria-label="Permalink to &quot;长运行Agent&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 2 模块的第 5 章。</p></blockquote><p>当 Agent 要跑几百轮怎么办？压缩、串行接力、环境管理——Anthropic 的方案教我们在坚持单 Agent 决策流的前提下突破上下文窗口的物理上限。</p><hr><h2 id="压缩策略" tabindex="-1">压缩策略 <a class="header-anchor" href="#压缩策略" aria-label="Permalink to &quot;压缩策略&quot;">​</a></h2><p>面对上下文溢出，压缩是第一道防线。但压缩是有损的——一段 10000 字的对话压缩成 500 字摘要，不可能保留所有细节。</p><p>Anthropic 在 Claude Code 中的做法：自动把历史对话传给模型，让它总结核心要点——关键决策、待解决问题、重要细节，清理掉冗余的工具调用结果，以最小信息损耗继续工作。先追求高召回尽量多保留信息，再逐步提高精度剔除重复无关的部分。</p><p><strong>结构化笔记</strong>则是一种更持久的做法。Agent 在工作过程中定期写笔记，把关键内容持久化到上下文之外的记忆系统。Claude Code 维护 <code>notes.md</code> 文件记录任务目标、未完成事项、依赖关系。即使上下文窗口被清空，AI 也能从笔记中恢复思路。</p><hr><h2 id="压缩与摘要的精细管理" tabindex="-1">压缩与摘要的精细管理 <a class="header-anchor" href="#压缩与摘要的精细管理" aria-label="Permalink to &quot;压缩与摘要的精细管理&quot;">​</a></h2><p>Menlo 将缩减操作严格划分为两种：<strong>压缩</strong>是可逆无损的外部化操作，用轻量级指针替代原始信息（文件路径替代文件内容、URL 替代网页 HTML）。<strong>摘要</strong>是有损不可逆操作，仅在压缩收益非常小时作为最后手段。</p><p>&quot;先卸载再摘要&quot;——执行摘要前将完整上下文写入日志文件，为不可逆操作买保险。</p><p>执行策略：定义浅腐烂阈值（128K-200K）作为触发器，达到时优先压缩，压缩收益变小后再用摘要。只压缩旧 50%，保留最新完整工具调用作为 Few-shot 示例——模型是强大的模仿者，如果看到的都是残缺格式会认为那是正确的。摘要必须基于完整版本，保留最后几个完整行动-观察对作为任务连续性的锚点。</p><hr><h2 id="串行接力-anthropic-的方案" tabindex="-1">串行接力：Anthropic 的方案 <a class="header-anchor" href="#串行接力-anthropic-的方案" aria-label="Permalink to &quot;串行接力：Anthropic 的方案&quot;">​</a></h2><p>单 Agent 决策统一但上下文窗口有限。当期待从&quot;写一个函数&quot;提高到&quot;开发复杂 Web 应用&quot;时，成千上万行代码会撑爆窗口。多 Agent 并行容易决策冲突，单 Agent 串行能力不够用。</p><p>Anthropic 的解决方案：一个 Agent，但分成两个阶段运行。</p><p><strong>初始化 Agent</strong>：只存在于项目第一天，不写业务代码，只搭架子——配服务器环境、建进度打卡表、初始化 Git 仓库，确保后续工作有据可查，把隐性知识变成显性文档。</p><p><strong>编码 Agent</strong>：真正干活的角色，在后续成百上千次会话中执行，但被施加严格约束——增量循环：每次醒来领一个任务，写完测试然后提交。</p><p>贯穿全文的核心概念是 <strong>Clean State（干净状态）</strong>：不管你这一班干了多少活，下班交接前必须保证代码能跑通、文档已更新，达到主分支合并标准，绝不能把编译报错的代码留给下一班。</p>',20)),(e(),E(s,null,{default:r(()=>[l(n,{id:"mermaid-56",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20Init%20as%20%E5%88%9D%E5%A7%8B%E5%8C%96%20Agent%0A%20%20%20%20participant%20Code%20as%20%E7%BC%96%E7%A0%81%20Agent%0A%20%20%20%20participant%20Git%20as%20Git%20%E4%BB%93%E5%BA%93%0A%20%20%20%20participant%20FS%20as%20%E6%96%87%E4%BB%B6%2F%E6%97%A5%E5%BF%97%0A%0A%20%20%20%20Init-%3E%3EGit%3A%20%E5%88%9D%E5%A7%8B%E5%8C%96%E4%BB%93%E5%BA%93%0A%20%20%20%20Init-%3E%3EFS%3A%20%E5%88%9B%E5%BB%BA%E8%BF%9B%E5%BA%A6%E8%A1%A8%20%2B%20%E7%8E%AF%E5%A2%83%E8%84%9A%E6%9C%AC%0A%20%20%20%20Init-%3E%3EFS%3A%20%E8%BE%93%E5%87%BA%3A%20%E5%88%9D%E5%A7%8B%E5%8C%96%E6%96%87%E6%A1%A3%0A%20%20%20%20Note%20over%20Init%3A%20%E4%BB%85%E5%AD%98%E5%9C%A8%E4%BA%8E%E7%AC%AC%E4%B8%80%E5%A4%A9%0A%0A%20%20%20%20loop%20%E6%88%90%E7%99%BE%E4%B8%8A%E5%8D%83%E6%AC%A1%E4%BC%9A%E8%AF%9D%0A%20%20%20%20%20%20%20%20Code-%3E%3EFS%3A%20%E8%AF%BB%E5%8F%96%E5%8A%9F%E8%83%BD%E6%B8%85%E5%8D%95%0A%20%20%20%20%20%20%20%20Code-%3E%3EFS%3A%20%E9%A2%86%E5%8F%96%E4%B8%80%E4%B8%AA%20passes%3Dfalse%20%E7%9A%84%E4%BB%BB%E5%8A%A1%0A%20%20%20%20%20%20%20%20Code-%3E%3ECode%3A%20%E5%AE%9E%E7%8E%B0%E5%8A%9F%E8%83%BD%20%2B%20%E5%86%99%E6%B5%8B%E8%AF%95%0A%20%20%20%20%20%20%20%20Code-%3E%3EGit%3A%20%E6%8F%90%E4%BA%A4%E4%BB%A3%E7%A0%81%0A%20%20%20%20%20%20%20%20Code-%3E%3EFS%3A%20%E6%9B%B4%E6%96%B0%E5%8A%9F%E8%83%BD%E6%B8%85%E5%8D%95%0A%20%20%20%20%20%20%20%20Code-%3E%3EGit%3A%20Clean%20State%20%E5%90%88%E5%B9%B6%0A%20%20%20%20%20%20%20%20Note%20over%20Code%3A%20%E5%BF%85%E9%A1%BB%E4%BF%9D%E8%AF%81%E4%BB%A3%E7%A0%81%E8%83%BD%E8%B7%91%E9%80%9A%0A%20%20%20%20end%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[i(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=a('<blockquote><p>💡 <strong>图解：</strong> Clean State 是跨会话接力的生命线——任何一班 Agent 都不能把烂摊子留给下一班。</p></blockquote><h3 id="外部记忆系统" tabindex="-1">外部记忆系统 <a class="header-anchor" href="#外部记忆系统" aria-label="Permalink to &quot;外部记忆系统&quot;">​</a></h3><p>既然内部记忆不可靠，就把记忆放到模型脑子之外。靠文件和日志而不是靠上下文来了解：</p><table tabindex="0"><thead><tr><th>问题</th><th>解决方案</th></tr></thead><tbody><tr><td>失忆</td><td>持久化日志和 Git 历史</td></tr><tr><td>信息不足导致猜测</td><td>结构化功能清单（JSON 格式）</td></tr><tr><td>贪多嚼不烂</td><td>一次只做一个功能，清单驱动</td></tr><tr><td>盲目自信</td><td>默认失败原则，必须完成测试才允许改为 true</td></tr><tr><td>烂尾文件污染</td><td>Clean State + Git 回滚</td></tr></tbody></table><hr><h2 id="启动序列" tabindex="-1">启动序列 <a class="header-anchor" href="#启动序列" aria-label="Permalink to &quot;启动序列&quot;">​</a></h2><p>每次会话对 Agent 来说都是一次从零开始，需要迅速恢复项目理解。标准步骤：定位（pwd 确认目录）→ 回忆（读进度记录和 Git 历史）→ 领任务（读功能清单找未通过条目）→ 复原（init.sh 启动环境）→ 验证（确认基础功能正常）→ 开始新开发。</p><p>功能清单采用 JSON 而非 Markdown——强结构性防止 Agent 编辑时造成结构破坏。Prompt 约束 Agent 只能修改 <code>passes</code> 字段，不得更改测试描述。</p><p>端到端测试用 Puppeteer：Agent 启动开发环境、执行用户交互行为、通过截图验证前端界面。不能只看后端数据库多了记录就宣布成功，需要视觉确认侧边栏变化、输入框清空等。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>压缩三技术：摘要压缩、结构化笔记、Sub-agent 架构</li><li>压缩 vs 摘要：可逆无损 vs 不可逆有损，先卸载再摘要</li><li>Anthropic 串行方案：初始化 Agent + 编码 Agent，Clean State 原则</li><li>启动序列：定位→回忆→领任务→复原→验证→开工</li><li>外部记忆系统靠文件和日志，不靠上下文窗口</li></ul><hr><p><strong>上一章</strong>: <a href="./04-Menlo的教训.html">Menlo的教训</a></p><hr><h2 id="模块总结" tabindex="-1">模块总结 <a class="header-anchor" href="#模块总结" aria-label="Permalink to &quot;模块总结&quot;">​</a></h2><p>上下文工程系列全部完结，共 5 章：</p><table tabindex="0"><thead><tr><th>章节</th><th>主题</th><th>核心洞察</th></tr></thead><tbody><tr><td>1</td><td>上下文的诅咒</td><td>Context Rot + 四种失效模式</td></tr><tr><td>2</td><td>三大支柱</td><td>卸载、缩减、隔离</td></tr><tr><td>3</td><td>动态上下文与实战</td><td>Cursor 五大实践、RAG vs Agentic Search</td></tr><tr><td>4</td><td>Menlo的教训</td><td>KV 缓存、文件系统即上下文</td></tr><tr><td>5</td><td>长运行Agent</td><td>压缩策略、串行接力、启动序列</td></tr></tbody></table><hr><p><a href="/">← 返回首页</a> | <a href="/03-Agent基础/">下一模块: Agent基础 →</a></p>',20))])}const m=o(p,[["render",h]]);export{b as __pageData,m as default};
